// ─── V2 — saveAgentMemory skips duplicates ──────────────────

// V-critere: V2
describe("[V2] saveAgentMemory skips duplicate (exact-match via resolveAgentMemoryConflict)", () => {
  test("returns 0 when content already exists (exact-match, action=skip)", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { saveAgentMemory } = await import("../../src/memory");

    const supabase = createMockSupabase({
      agent_memory: [
        {
          id: "existing-id",
          agent_role: "architect",
          content: "Pattern: dependency injection",
          tags: ["pattern-architectural"],
          importance_score: 75,
          metadata: {},
        },
      ],
    });

    // Same content — should be skipped
    const result = await saveAgentMemory(
      supabase,
      "architect",
      "Pattern: dependency injection", // exact same content
    );

    expect(result).toBe(0);
    // No new row inserted
    expect(supabase._getTable("agent_memory").length).toBe(1);
  });

  test("normalized content match triggers skip (case/whitespace insensitive)", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { saveAgentMemory } = await import("../../src/memory");

    const supabase = createMockSupabase({
      agent_memory: [
        {
          id: "existing-id",
          agent_role: "qa",
          content: "bug pattern: null pointer",
          tags: ["pattern-bug"],
          importance_score: 60,
          metadata: {},
        },
      ],
    });

    // Uppercase and extra whitespace — normalized should match
    const result = await saveAgentMemory(supabase, "qa", "  BUG PATTERN:  NULL POINTER  ");

    expect(result).toBe(0);
    expect(supabase._getTable("agent_memory").length).toBe(1);
  });

  test("different content inserts successfully (no false positive)", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { saveAgentMemory } = await import("../../src/memory");

    const supabase = createMockSupabase({
      agent_memory: [
        {
          id: "existing-id",
          agent_role: "architect",
          content: "Pattern: microservices architecture",
          tags: ["pattern-architectural"],
          importance_score: 70,
          metadata: {},
        },
      ],
    });

    const result = await saveAgentMemory(
      supabase,
      "architect",
      "Pattern: event-driven architecture",
    );

    expect(result).toBe(1);
    expect(supabase._getTable("agent_memory").length).toBe(2);
  });
});

