// ─── V16 — shares sum <= 1.0 ────────────────────────────────

// V-critere: V16
describe("[V16] sum of all shares in buildAgentContext sections is <= 1.0", () => {
  test("total shares without exploration <= 1.0 per spec 6.5", () => {
    // Without exploration per spec section 6.5:
    // CONTEXTE MEMOIRE: 0.20, SPRINT ACTUEL: 0.08, TACHES RECENTES: 0.11
    // GRAPHE CODE: 0.08, CONFIANCE AGENTS: 0.06, METRIQUES SPRINT: 0.08
    // DOCUMENTS PROJET: 0.08, PROFIL UTILISATEUR: 0.07, TACHES SIMILAIRES: 0.08
    // CONTEXTE CONVERSATION: 0.06, MEMOIRE ROLE: 0.10 (in CONTEXTE MEMOIRE budget)
    // Total = 1.00
    const shares = [0.2, 0.08, 0.11, 0.08, 0.06, 0.08, 0.08, 0.07, 0.08, 0.06, 0.1];
    const total = shares.reduce((a, b) => a + b, 0);
    expect(total).toBeLessThanOrEqual(1.0 + 0.001); // tolerance for floating point
    expect(Math.round(total * 100) / 100).toBe(1.0);
  });

  test("total shares with exploration <= 1.0 per spec 6.5", () => {
    // With exploration per spec section 6.5:
    // CONTEXTE MEMOIRE: 0.18, RAPPORT EXPLORATION: 0.10, SPRINT ACTUEL: 0.07
    // TACHES RECENTES: 0.09, GRAPHE CODE: 0.07, CONFIANCE AGENTS: 0.05
    // METRIQUES SPRINT: 0.06, DOCUMENTS PROJET: 0.07, PROFIL UTILISATEUR: 0.05
    // TACHES SIMILAIRES: 0.06, CONTEXTE CONVERSATION: 0.05, MEMOIRE ROLE: 0.08
    // Total = 0.93 (< 1.0, missing sections free up space)
    const shares = [0.18, 0.1, 0.07, 0.09, 0.07, 0.05, 0.06, 0.07, 0.05, 0.06, 0.05, 0.08];
    const total = shares.reduce((a, b) => a + b, 0);
    expect(total).toBeLessThanOrEqual(1.0);
    expect(Math.round(total * 100) / 100).toBe(0.93);
  });
});

