// ─── V20 — hard limit 15: evicts least important before insert

// V-critere: V20
describe("[V20] saveAgentMemory evicts least important entry when hard limit 15 reached", () => {
  test("DELETE called on lowest-score entry before INSERT when 15 entries exist", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { saveAgentMemory } = await import("../../src/memory");

    // Build 15 existing entries for the architect role
    const existingEntries = Array.from({ length: 15 }, (_, i) => ({
      id: `existing-${i}`,
      agent_role: "architect",
      content: `Existing pattern ${i}`,
      tags: ["pattern-architectural"],
      importance_score: 10 + i * 5, // scores: 10, 15, 20, ..., 80
      metadata: { graduated: false },
    }));

    const supabase = createMockSupabase({ agent_memory: existingEntries });

    await saveAgentMemory(supabase, "architect", "Brand new pattern to add");

    // The entry with id "existing-0" (importance_score=10, lowest) should be deleted
    const remainingRows = supabase._getTable("agent_memory");
    expect(remainingRows.length).toBe(15); // 14 remaining + 1 new
    const deletedEntry = remainingRows.find((r) => r.id === "existing-0");
    expect(deletedEntry).toBeUndefined(); // evicted
    const newEntry = remainingRows.find((r) => r.content === "Brand new pattern to add");
    expect(newEntry).toBeDefined();
  });

  test("no eviction when count < 15", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { saveAgentMemory } = await import("../../src/memory");

    const existingEntries = Array.from({ length: 14 }, (_, i) => ({
      id: `existing-${i}`,
      agent_role: "qa",
      content: `Existing bug pattern ${i}`,
      tags: ["pattern-bug"],
      importance_score: 50 + i,
      metadata: {},
    }));

    const supabase = createMockSupabase({ agent_memory: existingEntries });

    await saveAgentMemory(supabase, "qa", "New bug pattern");

    // 14 + 1 = 15 entries, no eviction
    const rows = supabase._getTable("agent_memory");
    expect(rows.length).toBe(15);
    // All original entries preserved
    const original0 = rows.find((r) => r.id === "existing-0");
    expect(original0).toBeDefined();
  });

  test("eviction targets the entry with lowest importance score", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { saveAgentMemory } = await import("../../src/memory");

    const entries = [
      {
        id: "low-score",
        agent_role: "sm",
        content: "Old processus",
        tags: ["processus"],
        importance_score: 1,
        metadata: {},
      },
      ...Array.from({ length: 14 }, (_, i) => ({
        id: `high-${i}`,
        agent_role: "sm",
        content: `Important pattern ${i}`,
        tags: ["processus"],
        importance_score: 80 + i,
        metadata: {},
      })),
    ];

    const supabase = createMockSupabase({ agent_memory: entries });

    await saveAgentMemory(supabase, "sm", "New sprint retrospective insight");

    const rows = supabase._getTable("agent_memory");
    // low-score entry should be evicted
    const lowScoreEntry = rows.find((r) => r.id === "low-score");
    expect(lowScoreEntry).toBeUndefined();
  });
});

