describe("resolveAgentMemoryConflict (regression guard)", () => {
  test("returns insert when supabase is null", async () => {
    const { resolveAgentMemoryConflict } = await import("../../src/memory");
    const result = await resolveAgentMemoryConflict(null, "architect", "some content");
    expect(result.action).toBe("insert");
  });

  test("returns insert when no matching entry found", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { resolveAgentMemoryConflict } = await import("../../src/memory");

    const supabase = createMockSupabase({ agent_memory: [] });
    const result = await resolveAgentMemoryConflict(supabase, "qa", "new content");
    expect(result.action).toBe("insert");
  });

  test("returns skip with existingId when exact match found", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { resolveAgentMemoryConflict } = await import("../../src/memory");

    const supabase = createMockSupabase({
      agent_memory: [
        {
          id: "uuid-1",
          agent_role: "qa",
          content: "duplicate content",
          tags: [],
          importance_score: 50,
          metadata: {},
        },
      ],
    });
    const result = await resolveAgentMemoryConflict(supabase, "qa", "duplicate content");
    expect(result.action).toBe("skip");
    expect(result.existingId).toBe("uuid-1");
  });

  test("role isolation: same content for different role is not a duplicate", async () => {
    const { createMockSupabase } = await import("../fixtures/mock-supabase");
    const { resolveAgentMemoryConflict } = await import("../../src/memory");

    const supabase = createMockSupabase({
      agent_memory: [
        {
          id: "uuid-2",
          agent_role: "architect",
          content: "shared pattern",
          tags: [],
          importance_score: 70,
          metadata: {},
        },
      ],
    });
    // Same content, but different role (qa) — should be insert
    const result = await resolveAgentMemoryConflict(supabase, "qa", "shared pattern");
    expect(result.action).toBe("insert");
  });
});

